const rootEnvelope = $json.body ?? $json;
const headers = $json.headers ?? rootEnvelope.headers ?? {};
const lowerHeaders = Object.fromEntries(Object.entries(headers).map(([k, v]) => [String(k).toLowerCase(), v]));

const inboundSource = $json.__inbound_source ?? rootEnvelope.__inbound_source ?? null;
const inboundChannel = $json.__inbound_channel ?? rootEnvelope.__inbound_channel ?? null;
const provider = $json.__provider ?? rootEnvelope.__provider ?? null;
const expectedReturn = $json.__expected_return ?? rootEnvelope.__expected_return ?? 'webhook';

const args =
  rootEnvelope.args ??
  rootEnvelope.arguments ??
  rootEnvelope.input ??
  rootEnvelope.parameters ??
  rootEnvelope.data ??
  rootEnvelope.message ??
  rootEnvelope;

function clean(v) {
  return v === undefined || v === null || v === '' || v === 'null' ? null : v;
}

function asString(v) {
  return v === undefined || v === null ? null : String(v);
}

function normalizeAction(value) {
  const raw = String(value ?? '').trim().toLowerCase();
  const aliases = {
    'restaurant_context': 'get_restaurant_context',
    'get_context': 'get_restaurant_context',
    'context': 'get_restaurant_context',
    'availability': 'check_availability',
    'check_slot': 'check_availability',
    'check': 'check_availability',
    'reserve': 'create_reservation',
    'book': 'create_reservation',
    'confirm_reservation': 'create_reservation',
    'create_booking': 'create_reservation',
    'log': 'log_conversation',
    'call_log': 'log_conversation',
    'message': 'message_inbound',
    'inbound': 'message_inbound',
    'incoming_message': 'message_inbound'
  };
  return aliases[raw] ?? raw;
}

function sqlString(value) {
  if (value === null || value === undefined || value === '') return 'NULL';
  return `'${String(value).replace(/'/g, "''")}'`;
}

function sqlNumber(value) {
  if (value === null || value === undefined || value === '' || Number.isNaN(Number(value))) return 'NULL';
  return String(Number(value));
}

function sqlBoolean(value) {
  return value === true || value === 'true' || value === 1 || value === '1' ? 'TRUE' : 'FALSE';
}

function sqlJson(value) {
  if (value === null || value === undefined) return 'NULL';
  return `'${JSON.stringify(value).replace(/'/g, "''")}'::jsonb`;
}

const functionAction = normalizeAction(
  clean(rootEnvelope.function_name) ??
  clean(rootEnvelope.name) ??
  clean(rootEnvelope.action) ??
  clean(args.function_name) ??
  clean(args.name) ??
  clean(args.action)
);

const source =
  clean(args.source) ??
  clean(rootEnvelope.source) ??
  clean(inboundSource) ??
  'webhook';

const channel =
  clean(args.channel) ??
  clean(rootEnvelope.channel) ??
  clean(inboundChannel) ??
  (source === 'retell_voice' ? 'phone' : source === 'retell_sms' ? 'sms' : source === 'email' ? 'email' : source === 'instagram' ? 'instagram' : 'webhook');

const action = functionAction || (
  source === 'retell_voice' || source === 'retell_sms'
    ? 'get_restaurant_context'
    : 'message_inbound'
);

const callId =
  clean(rootEnvelope.call_id) ??
  clean(rootEnvelope.call?.call_id) ??
  clean(args.call_id) ??
  clean(args.call?.call_id);

const smsId =
  clean(rootEnvelope.sms_id) ??
  clean(rootEnvelope.message_id) ??
  clean(rootEnvelope.sms?.id) ??
  clean(args.sms_id) ??
  clean(args.message_id) ??
  clean(args.sms?.id);

const emailMessageId =
  clean(rootEnvelope.email_message_id) ??
  clean(rootEnvelope.mail?.message_id) ??
  clean(args.email_message_id) ??
  clean(args.message_id);

const instagramMessageId =
  clean(rootEnvelope.instagram_message_id) ??
  clean(rootEnvelope.entry?.[0]?.messaging?.[0]?.message?.mid) ??
  clean(args.instagram_message_id) ??
  clean(args.message_id);

const from =
  clean(args.from) ??
  clean(args.caller) ??
  clean(args.phone) ??
  clean(rootEnvelope.from) ??
  clean(rootEnvelope.call?.from_number) ??
  clean(rootEnvelope.call?.from) ??
  clean(rootEnvelope.sms?.from) ??
  clean(rootEnvelope.mail?.from) ??
  clean(rootEnvelope.entry?.[0]?.messaging?.[0]?.sender?.id);

const to =
  clean(args.to) ??
  clean(rootEnvelope.to) ??
  clean(rootEnvelope.call?.to_number) ??
  clean(rootEnvelope.call?.to) ??
  clean(rootEnvelope.sms?.to) ??
  clean(rootEnvelope.mail?.to) ??
  clean(rootEnvelope.entry?.[0]?.messaging?.[0]?.recipient?.id);

const phone =
  clean(args.phone) ??
  clean(args.caller_phone) ??
  (channel === 'phone' || channel === 'sms' ? clean(from) : null);

const email =
  clean(args.email) ??
  clean(args.customer_email) ??
  clean(rootEnvelope.email) ??
  clean(rootEnvelope.mail?.from);

const restaurantSlug =
  clean(args.restaurant_slug) ??
  clean(args.slug) ??
  clean(rootEnvelope.restaurant_slug) ??
  clean(rootEnvelope.slug) ??
  clean(rootEnvelope.metadata?.restaurant_slug) ??
  clean(args.metadata?.restaurant_slug);

const conversationId =
  clean(args.conversation_id) ??
  clean(rootEnvelope.conversation_id) ??
  (callId ? `retell-call-${callId}` : null) ??
  (smsId ? `retell-sms-${smsId}` : null) ??
  (emailMessageId ? `email-${emailMessageId}` : null) ??
  (instagramMessageId ? `instagram-${instagramMessageId}` : null) ??
  (from ? `${source}-${from}` : null) ??
  `${source}-${Date.now()}`;

const userMessage =
  clean(args.user_message) ??
  clean(args.message) ??
  clean(args.text) ??
  clean(args.transcript) ??
  clean(rootEnvelope.user_message) ??
  clean(rootEnvelope.message?.text) ??
  clean(rootEnvelope.message) ??
  clean(rootEnvelope.text) ??
  clean(rootEnvelope.sms?.text) ??
  clean(rootEnvelope.mail?.text) ??
  clean(rootEnvelope.mail?.subject) ??
  clean(rootEnvelope.entry?.[0]?.messaging?.[0]?.message?.text) ??
  '';

const requestedDatetime =
  clean(args.requested_datetime) ??
  clean(args.start_time) ??
  clean(args.datetime) ??
  clean(rootEnvelope.requested_datetime);

const partySize =
  clean(args.party_size) ??
  clean(args.people) ??
  clean(args.guests) ??
  clean(rootEnvelope.party_size);

const fullName =
  clean(args.full_name) ??
  clean(args.name_for_reservation) ??
  clean(args.customer_name) ??
  clean(rootEnvelope.full_name) ??
  clean(rootEnvelope.mail?.from_name);

const specialRequest =
  clean(args.special_request) ??
  clean(args.special_requests) ??
  clean(args.note) ??
  clean(rootEnvelope.special_request);

const customerConfirmed =
  args.customer_confirmed ??
  args.confirmed ??
  rootEnvelope.customer_confirmed ??
  false;

const summary =
  clean(args.summary) ??
  clean(rootEnvelope.summary) ??
  clean(rootEnvelope.call?.call_analysis?.call_summary);

const transcript =
  clean(args.transcript) ??
  clean(rootEnvelope.transcript) ??
  clean(rootEnvelope.call?.transcript);

const externalEventId =
  clean(args.external_event_id) ??
  clean(rootEnvelope.external_event_id) ??
  clean(rootEnvelope.event_id) ??
  clean(callId) ??
  clean(smsId) ??
  clean(emailMessageId) ??
  clean(instagramMessageId) ??
  conversationId;

const retellSignature = clean(lowerHeaders['x-retell-signature']);

const allowedSources = ['retell_voice', 'retell_sms', 'email', 'instagram', 'webhook', 'telegram_debug'];

return [{
  json: {
    action,
    source,
    channel,
    provider,
    expected_return: expectedReturn,
    inbound_source: inboundSource,
    inbound_channel: inboundChannel,
    source_allowed: allowedSources.includes(source),
    source_matches_entrypoint: source === inboundSource,
    retell_signature_present: !!retellSignature,
    retell_signature_status: retellSignature ? 'present_not_cryptographically_verified_in_blueprint' : 'missing',
    source_verification_status:
      source.startsWith('retell')
        ? (source === inboundSource && provider === 'retell' && retellSignature ? 'soft_verified_signature_present' : 'retell_unverified_signature_missing_or_source_mismatch')
        : (source === inboundSource ? 'soft_verified_by_entrypoint' : 'source_mismatch'),

    conversation_id: conversationId,
    external_event_id: externalEventId,
    call_id: callId,
    sms_id: smsId,
    email_message_id: emailMessageId,
    instagram_message_id: instagramMessageId,

    restaurant_slug: restaurantSlug,
    to,
    from,
    phone,
    email,
    full_name: fullName,
    user_message: userMessage,
    raw_message: userMessage,
    requested_datetime: requestedDatetime,
    party_size: partySize === null ? null : Number(partySize),
    special_request: specialRequest,
    customer_confirmed: customerConfirmed === true || customerConfirmed === 'true' || customerConfirmed === 1 || customerConfirmed === '1',
    summary,
    transcript,

    action_sql: sqlString(action),
    source_sql: sqlString(source),
    channel_sql: sqlString(channel),
    provider_sql: sqlString(provider),
    conversation_id_sql: sqlString(conversationId),
    external_event_id_sql: sqlString(externalEventId),
    call_id_sql: sqlString(callId),
    sms_id_sql: sqlString(smsId),
    email_message_id_sql: sqlString(emailMessageId),
    instagram_message_id_sql: sqlString(instagramMessageId),
    restaurant_slug_sql: sqlString(restaurantSlug),
    to_sql: sqlString(to),
    from_sql: sqlString(from),
    phone_sql: sqlString(phone),
    email_sql: sqlString(email),
    full_name_sql: sqlString(fullName),
    user_message_sql: sqlString(userMessage),
    requested_datetime_sql: sqlString(requestedDatetime),
    party_size_sql: sqlNumber(partySize),
    special_request_sql: sqlString(specialRequest),
    customer_confirmed_sql: sqlBoolean(customerConfirmed),
    summary_sql: sqlString(summary),
    transcript_sql: sqlString(transcript),
    raw_payload_sql: sqlJson(rootEnvelope),

    raw_payload: rootEnvelope,
    headers
  }
}];

const input = $json;

const isRetell = ['retell_voice', 'retell_sms'].includes(input.source);
const hardReject = false;

let warnings = [];
if (!input.source_allowed) warnings.push('SOURCE_NOT_ALLOWED');
if (!input.source_matches_entrypoint) warnings.push('SOURCE_ENTRYPOINT_MISMATCH');
if (isRetell && !input.retell_signature_present) warnings.push('RETELL_SIGNATURE_MISSING');

return [{
  json: {
    ...input,
    is_retell_source: isRetell,
    source_warnings: warnings,
    source_verified_for_test: input.source_allowed && input.source_matches_entrypoint,
    source_verified_cryptographically: false,
    reject_request: hardReject && warnings.length > 0
  }
}];

function nodeJson(name) {
  try {
    return $(name).item.json || {};
  } catch (e) {
    return {};
  }
}

function hasValue(v) {
  return v !== undefined && v !== null && v !== '';
}

function readFieldFrom(obj, field) {
  const candidates = [
    obj?.[field],
    obj?.body?.[field],
    obj?.body?.args?.[field],
    obj?.body?.arguments?.[field],
    obj?.args?.[field],
    obj?.arguments?.[field],
    obj?.query?.[field]
  ];

  return candidates.find(hasValue);
}

const verifyJson = nodeJson('Verify Channel Source');
const webhookJson = nodeJson('Webhook Retell Voice Function');
const markJson = nodeJson('Mark Retell Voice Source');

function pickField(field, fallback = null) {
  const sources = [
    verifyJson,
    markJson,
    webhookJson
  ];

  for (const source of sources) {
    const value = readFieldFrom(source, field);
    if (hasValue(value)) return value;
  }

  return fallback;
}

const req = {
  ...verifyJson,

  date_text: pickField('date_text', verifyJson.date_text),
  time_text: pickField('time_text', verifyJson.time_text),
  current_datetime: pickField('current_datetime', verifyJson.current_datetime),
  restaurant_timezone: pickField('restaurant_timezone', verifyJson.restaurant_timezone),

  requested_datetime: pickField('requested_datetime', verifyJson.requested_datetime),
  party_size: pickField('party_size', verifyJson.party_size),
  full_name: pickField('full_name', verifyJson.full_name),
  phone: pickField('phone', verifyJson.phone),
  email: pickField('email', verifyJson.email),
  special_request: pickField('special_request', verifyJson.special_request),
  customer_confirmed: pickField('customer_confirmed', verifyJson.customer_confirmed),
  restaurant_slug: pickField('restaurant_slug', verifyJson.restaurant_slug),
  conversation_id: pickField('conversation_id', verifyJson.conversation_id)
};

const restaurant = $('Lookup Restaurant Context').item.json;
const closure = $('Check Closure For Request').item.json;
const existing = $('Check Existing Reservation').item.json;
const client = $('Upsert Client When Needed').item.json;
const reservation = $('Create Reservation When Needed').item.json;
const log = $('Save Channel Log').item.json;

function bool(v) {
  return v === true || v === 'true' || v === 1 || v === '1';
}

function pad(n) {
  return String(n).padStart(2, '0');
}

function normalizeText(v) {
  return String(v || '')
    .toLowerCase()
    .normalize('NFD')
    .replace(/[\u0300-\u036f]/g, '')
    .replace(/[’']/g, ' ')
    .replace(/-/g, ' ')
    .replace(/\s+/g, ' ')
    .trim();
}

function formatDateHumanFr(iso, timezone = 'Europe/Paris') {
  if (!iso) return null;

  const d = new Date(iso);
  if (Number.isNaN(d.getTime())) return null;

  const date = d.toLocaleDateString('fr-FR', {
    weekday: 'long',
    day: 'numeric',
    month: 'long',
    year: 'numeric',
    timeZone: timezone
  });

  const parts = new Intl.DateTimeFormat('fr-FR', {
    hour: 'numeric',
    minute: '2-digit',
    hour12: false,
    timeZone: timezone
  }).formatToParts(d);

  const hour = Number(parts.find(p => p.type === 'hour')?.value ?? 0);
  const minute = Number(parts.find(p => p.type === 'minute')?.value ?? 0);

  let timeLabel;

  if (hour === 12 && minute === 0) {
    timeLabel = 'midi';
  } else if (hour === 12 && minute === 30) {
    timeLabel = 'midi trente';
  } else if (minute === 0) {
    timeLabel = `${hour} heure${hour > 1 ? 's' : ''}`;
  } else {
    timeLabel = `${hour}h${pad(minute)}`;
  }

  return `${date} à ${timeLabel}`;
}

function getTimezoneOffsetMinutes(date, timeZone) {
  const dtf = new Intl.DateTimeFormat('en-US', {
    timeZone,
    hour12: false,
    year: 'numeric',
    month: '2-digit',
    day: '2-digit',
    hour: '2-digit',
    minute: '2-digit',
    second: '2-digit'
  });

  const parts = dtf.formatToParts(date).reduce((acc, part) => {
    if (part.type !== 'literal') acc[part.type] = part.value;
    return acc;
  }, {});

  const asUTC = Date.UTC(
    Number(parts.year),
    Number(parts.month) - 1,
    Number(parts.day),
    Number(parts.hour),
    Number(parts.minute),
    Number(parts.second)
  );

  return (asUTC - date.getTime()) / 60000;
}

function offsetToString(offsetMinutes) {
  const sign = offsetMinutes >= 0 ? '+' : '-';
  const abs = Math.abs(offsetMinutes);
  const h = Math.floor(abs / 60);
  const m = abs % 60;
  return `${sign}${pad(h)}:${pad(m)}`;
}

function makeZonedIso(year, monthIndex, day, hour, minute, timezone = 'Europe/Paris') {
  const utcGuess = new Date(Date.UTC(year, monthIndex, day, hour, minute, 0));
  let offset = getTimezoneOffsetMinutes(utcGuess, timezone);

  let utcDate = new Date(Date.UTC(year, monthIndex, day, hour, minute, 0) - offset * 60000);
  offset = getTimezoneOffsetMinutes(utcDate, timezone);

  utcDate = new Date(Date.UTC(year, monthIndex, day, hour, minute, 0) - offset * 60000);

  return {
    iso: `${year}-${pad(monthIndex + 1)}-${pad(day)}T${pad(hour)}:${pad(minute)}:00${offsetToString(offset)}`,
    utcDate,
    offset
  };
}

function getParisParts(date, timezone = 'Europe/Paris') {
  const parts = new Intl.DateTimeFormat('fr-FR', {
    timeZone: timezone,
    year: 'numeric',
    month: '2-digit',
    day: '2-digit',
    weekday: 'long',
    hour: '2-digit',
    minute: '2-digit',
    hour12: false
  }).formatToParts(date).reduce((acc, part) => {
    if (part.type !== 'literal') acc[part.type] = part.value;
    return acc;
  }, {});

  const weekdays = {
    dimanche: 0,
    lundi: 1,
    mardi: 2,
    mercredi: 3,
    jeudi: 4,
    vendredi: 5,
    samedi: 6
  };

  return {
    year: Number(parts.year),
    monthIndex: Number(parts.month) - 1,
    day: Number(parts.day),
    weekday: weekdays[normalizeText(parts.weekday)],
    hour: Number(parts.hour),
    minute: Number(parts.minute)
  };
}

function wordsToNumber(text) {
  const t = normalizeText(text);

  const numbers = {
    'un': 1,
    'une': 1,
    'deux': 2,
    'trois': 3,
    'quatre': 4,
    'cinq': 5,
    'six': 6,
    'sept': 7,
    'huit': 8,
    'neuf': 9,
    'dix': 10,
    'onze': 11,
    'douze': 12,
    'treize': 13,
    'quatorze': 14,
    'quinze': 15,
    'seize': 16,
    'dix sept': 17,
    'dix huit': 18,
    'dix neuf': 19,
    'vingt': 20,
    'vingt et un': 21,
    'vingt et une': 21,
    'vingt deux': 22,
    'vingt trois': 23,
    'vingt quatre': 24,
    'vingt cinq': 25,
    'vingt six': 26,
    'vingt sept': 27,
    'vingt huit': 28,
    'vingt neuf': 29,
    'trente': 30,
    'trente et un': 31
  };

  if (/^\d+$/.test(t)) return Number(t);

  return numbers[t] ?? null;
}

function parseDateText(dateText, currentDate, timezone = 'Europe/Paris') {
  const raw = normalizeText(dateText);
  const base = getParisParts(currentDate, timezone);

  const weekdays = {
    dimanche: 0,
    lundi: 1,
    mardi: 2,
    mercredi: 3,
    jeudi: 4,
    vendredi: 5,
    samedi: 6
  };

  const months = {
    janvier: 0,
    fevrier: 1,
    mars: 2,
    avril: 3,
    mai: 4,
    juin: 5,
    juillet: 6,
    aout: 7,
    septembre: 8,
    octobre: 9,
    novembre: 10,
    decembre: 11
  };

  let year = base.year;
  let monthIndex = base.monthIndex;
  let day = base.day;

  if (raw.includes('aujourd')) {
    return { year, monthIndex, day };
  }

  if (raw.includes('demain')) {
    const d = new Date(Date.UTC(base.year, base.monthIndex, base.day, 12, 0, 0));
    d.setUTCDate(d.getUTCDate() + 1);
    return {
      year: d.getUTCFullYear(),
      monthIndex: d.getUTCMonth(),
      day: d.getUTCDate()
    };
  }

  const absoluteMatch = raw.match(/(?:lundi|mardi|mercredi|jeudi|vendredi|samedi|dimanche)?\s*(\d{1,2}|un|une|deux|trois|quatre|cinq|six|sept|huit|neuf|dix|onze|douze|treize|quatorze|quinze|seize|dix sept|dix huit|dix neuf|vingt|vingt et un|vingt et une|vingt deux|vingt trois|vingt quatre|vingt cinq|vingt six|vingt sept|vingt huit|vingt neuf|trente|trente et un)\s+(janvier|fevrier|mars|avril|mai|juin|juillet|aout|septembre|octobre|novembre|decembre)(?:\s+(\d{4}|deux mille vingt six|deux mille vingt sept))?/);

  if (absoluteMatch) {
    const parsedDay = wordsToNumber(absoluteMatch[1]);
    const parsedMonth = months[absoluteMatch[2]];

    let parsedYear = base.year;

    if (absoluteMatch[3]) {
      const y = normalizeText(absoluteMatch[3]);
      if (/^\d{4}$/.test(y)) parsedYear = Number(y);
      if (y === 'deux mille vingt six') parsedYear = 2026;
      if (y === 'deux mille vingt sept') parsedYear = 2027;
    }

    const candidate = makeZonedIso(parsedYear, parsedMonth, parsedDay, 12, 0, timezone).utcDate;

    if (candidate < currentDate && !absoluteMatch[3]) {
      parsedYear += 1;
    }

    return {
      year: parsedYear,
      monthIndex: parsedMonth,
      day: parsedDay
    };
  }

  for (const [weekdayName, targetWeekday] of Object.entries(weekdays)) {
    if (raw.includes(weekdayName)) {
      let delta = (targetWeekday - base.weekday + 7) % 7;

      if (delta === 0) {
        delta = 7;
      }

      const d = new Date(Date.UTC(base.year, base.monthIndex, base.day, 12, 0, 0));
      d.setUTCDate(d.getUTCDate() + delta);

      return {
        year: d.getUTCFullYear(),
        monthIndex: d.getUTCMonth(),
        day: d.getUTCDate()
      };
    }
  }

  return null;
}

function parseTimeText(dateText, timeText) {
  const raw = normalizeText(`${dateText || ''} ${timeText || ''}`);

  if (raw.includes('midi trente') || raw.includes('midi et demi') || raw.includes('12h30') || raw.includes('12 h 30')) {
    return { hour: 12, minute: 30 };
  }

  if (raw.includes('midi quart') || raw.includes('midi et quart') || raw.includes('12h15') || raw.includes('12 h 15')) {
    return { hour: 12, minute: 15 };
  }

  if (raw.includes('midi moins le quart') || raw.includes('11h45') || raw.includes('11 h 45')) {
    return { hour: 11, minute: 45 };
  }

  if (raw.includes('midi')) {
    return { hour: 12, minute: 0 };
  }

  if (raw.includes('soir')) {
    const explicitTime = parseExplicitTime(raw);
    if (explicitTime) {
      if (explicitTime.hour >= 1 && explicitTime.hour <= 11) {
        explicitTime.hour += 12;
      }
      return explicitTime;
    }

    return { hour: 19, minute: 0 };
  }

  const explicitTime = parseExplicitTime(raw);
  if (explicitTime) return explicitTime;

  return null;
}

function parseExplicitTime(raw) {
  let match = raw.match(/(\d{1,2})\s*h\s*(\d{1,2})?/);
  if (match) {
    return {
      hour: Number(match[1]),
      minute: match[2] ? Number(match[2]) : 0
    };
  }

  match = raw.match(/(\d{1,2})\s*:\s*(\d{2})/);
  if (match) {
    return {
      hour: Number(match[1]),
      minute: Number(match[2])
    };
  }

  match = raw.match(/(\d{1,2})\s*heures?\s*(\d{1,2})?/);
  if (match) {
    return {
      hour: Number(match[1]),
      minute: match[2] ? Number(match[2]) : 0
    };
  }

  const wordHours = [
    ['vingt trois', 23],
    ['vingt deux', 22],
    ['vingt et une', 21],
    ['vingt et un', 21],
    ['vingt', 20],
    ['dix neuf', 19],
    ['dix huit', 18],
    ['dix sept', 17],
    ['seize', 16],
    ['quinze', 15],
    ['quatorze', 14],
    ['treize', 13],
    ['douze', 12],
    ['onze', 11],
    ['dix', 10],
    ['neuf', 9],
    ['huit', 8],
    ['sept', 7],
    ['six', 6],
    ['cinq', 5],
    ['quatre', 4],
    ['trois', 3],
    ['deux', 2],
    ['une', 1],
    ['un', 1]
  ];

  for (const [label, hour] of wordHours) {
    if (raw.includes(`${label} heure`) || raw.includes(`${label} heures`)) {
      let minute = 0;

      if (raw.includes('trente')) minute = 30;
      if (raw.includes('quart')) minute = 15;
      if (raw.includes('moins le quart')) {
        return {
          hour: hour - 1,
          minute: 45
        };
      }

      return { hour, minute };
    }
  }

  return null;
}

const restaurantFound = bool(restaurant.restaurant_found);
const isClosed = bool(closure.is_closed);
const reservationExists = bool(existing.reservation_exists);
const reservationCreated = bool(reservation.reservation_created);
const logSaved = bool(log.log_saved);

const timezone = restaurant.timezone || req.restaurant_timezone || 'Europe/Paris';
const humanDate = formatDateHumanFr(req.requested_datetime, timezone);
const missing = [];

if (['check_availability', 'create_reservation'].includes(req.action)) {
  if (!req.requested_datetime) missing.push('requested_datetime');
  if (!req.party_size) missing.push('party_size');
}

if (req.action === 'create_reservation') {
  if (!req.full_name) missing.push('full_name');
  if (!req.customer_confirmed) missing.push('customer_confirmed');
}

let response = {
  ok: false,
  action: req.action || 'unknown',
  source: req.source,
  channel: req.channel,
  provider: req.provider,
  conversation_id: req.conversation_id,
  external_event_id: req.external_event_id,
  source_verified_for_test: req.source_verified_for_test,
  source_verified_cryptographically: req.source_verified_cryptographically,
  source_verification_status: req.source_verification_status,
  source_warnings: req.source_warnings || [],
  restaurant_found: restaurantFound,
  restaurant_id: restaurant.restaurant_id ?? null,
  restaurant_slug: restaurant.restaurant_slug ?? req.restaurant_slug ?? null,
  restaurant_name: restaurant.restaurant_name ?? null,
  decision: 'technical_error',
  reply: "Désolé, je rencontre un problème technique. Le restaurant pourra reprendre la demande directement.",
  needs_followup: false,
  missing_fields: [],
  available: false,
  confirmed: false,
  duplicate: false,
  reservation_id: null,
  client_id: null,
  log_saved: logSaved,
  log_id: log.log_id ?? null,
  error_code: null,
  async_outbound_required: ['email', 'instagram'].includes(req.source)
};

if (req.requested_datetime) {
  response.requested_datetime = req.requested_datetime;
  response.resolved_requested_datetime = req.requested_datetime;
  response.human_date = humanDate;
  response.resolved_human_date = humanDate;
  response.restaurant_timezone = timezone;
}

if (req.party_size) {
  response.party_size = Number(req.party_size);
}

if (req.full_name) {
  response.full_name = req.full_name;
}

const supportedActions = [
  'get_restaurant_context',
  'resolve_reservation_datetime',
  'check_availability',
  'create_reservation',
  'log_conversation',
  'message_inbound'
];

if (!req.action || !supportedActions.includes(req.action)) {
  response.error_code = 'UNSUPPORTED_ACTION';
  response.decision = 'technical_error';
  response.reply = "Action non prise en charge par le service de réservation.";
  return [{ json: response }];
}

if (!restaurantFound && req.action !== 'log_conversation') {
  response.error_code = 'RESTAURANT_NOT_FOUND';
  response.decision = 'need_human';
  response.reply = "Je suis désolé, je n’arrive pas à identifier le restaurant concerné. Pouvez-vous vérifier le canal utilisé ou rappeler le restaurant directement ?";
  return [{ json: response }];
}

const requestedDate = req.requested_datetime ? new Date(req.requested_datetime) : null;
const now = new Date();

const requestedDateIsInvalid =
  req.requested_datetime &&
  (Number.isNaN(requestedDate.getTime()) || requestedDate < now);

if (['check_availability', 'create_reservation'].includes(req.action) && requestedDateIsInvalid) {
  response.ok = false;
  response.decision = 'date_clarification_needed';
  response.available = false;
  response.confirmed = false;
  response.error_code = 'REQUESTED_DATETIME_IN_PAST';
  response.reply = "Je n’ai pas pu interpréter correctement la date. Pouvez-vous me donner la date complète, par exemple mercredi 22 juillet ?";
  response.missing_fields = ['requested_datetime'];
  return [{ json: response }];
}

if (req.action === 'message_inbound') {
  response.ok = true;
  response.decision = 'message_received_needs_core_agent';
  response.needs_followup = true;
  response.reply = "Bonjour, votre demande est bien reçue. Pouvez-vous préciser la date, l’heure, le nombre de personnes et le nom pour la réservation ?";
  response.missing_fields = ['requested_datetime', 'party_size', 'full_name'];
  response.note = "Blueprint router: à remplacer ensuite par l’appel au Reservation Core / Agent Conversationnel.";
  return [{ json: response }];
}

if (req.action === 'get_restaurant_context') {
  const currentDatetime = new Date();

  response.ok = true;
  response.decision = 'context_ready';
  response.reply = `Vous êtes l’agent de réservation du restaurant ${restaurant.restaurant_name}.`;
  response.available = null;
  response.context = {
    restaurant_id: restaurant.restaurant_id,
    restaurant_slug: restaurant.restaurant_slug,
    restaurant_name: restaurant.restaurant_name,
    timezone,
    current_datetime: currentDatetime.toISOString(),
    current_datetime_human: formatDateHumanFr(currentDatetime.toISOString(), timezone),
    max_party_size: Number(restaurant.max_party_size || 12),
    default_meal_duration_minutes: Number(restaurant.default_meal_duration_minutes || 120),
    cleaning_buffer_minutes: Number(restaurant.cleaning_buffer_minutes || 15),
    booking_policy: restaurant.booking_policy ?? null,
    event_notification_policy: restaurant.event_notification_policy ?? null
  };
  return [{ json: response }];
}

if (req.action === 'resolve_reservation_datetime') {
  const dateText = req.date_text || '';
  const timeText = req.time_text || '';
  const currentDatetimeRaw = req.current_datetime || new Date().toISOString();
  const currentDate = new Date(currentDatetimeRaw);

  if (!dateText) {
    response.ok = false;
    response.decision = 'datetime_clarification_needed';
    response.error_code = 'DATE_TEXT_MISSING';
    response.reply = "Pour quel jour souhaitez-vous réserver ?";
    response.missing_fields = ['date_text'];
    return [{ json: response }];
  }

  if (!timeText) {
    response.ok = false;
    response.decision = 'datetime_clarification_needed';
    response.error_code = 'TIME_TEXT_MISSING';
    response.reply = "Pour quel horaire souhaitez-vous réserver ?";
    response.missing_fields = ['time_text'];
    return [{ json: response }];
  }

  if (Number.isNaN(currentDate.getTime())) {
    response.ok = false;
    response.decision = 'datetime_clarification_needed';
    response.error_code = 'INVALID_CURRENT_DATETIME';
    response.reply = "Je n’arrive pas à interpréter la date actuelle. Pouvez-vous me donner la date complète ?";
    response.missing_fields = ['current_datetime'];
    return [{ json: response }];
  }
  const resolvedDate = parseDateText(dateText, currentDate, timezone);
  const resolvedTime = parseTimeText(dateText, timeText);

  const normalizedTimeText = normalizeText(timeText);
  const normalizedDateText = normalizeText(dateText);
  const normalizedFullText = `${normalizedDateText} ${normalizedTimeText}`;

  /**
   * Protection restaurant :
   * Une heure entre 1 et 6 est ambiguë.
   * Exemple : "une heure et quart" peut vouloir dire 1h15 ou 13h15.
   * On ne doit pas confirmer automatiquement.
   */
  if (
    resolvedTime &&
    resolvedTime.hour >= 1 &&
    resolvedTime.hour <= 6 &&
    !normalizedFullText.includes('matin') &&
    !normalizedFullText.includes('apres midi') &&
    !normalizedFullText.includes('apres-midi') &&
    !normalizedFullText.includes('soir') &&
    !normalizedFullText.includes('dejeuner') &&
    !normalizedFullText.includes('diner') &&
    !normalizedFullText.includes('déjeuner') &&
    !normalizedFullText.includes('dîner')
  ) {
    response.ok = false;
    response.decision = 'time_clarification_needed';
    response.error_code = 'AMBIGUOUS_RESTAURANT_TIME';
    response.available = false;
    response.confirmed = false;
    response.reply = `Pour confirmer, vous voulez dire ${resolvedTime.hour + 12}h${resolvedTime.minute ? pad(resolvedTime.minute) : ''} ?`;
    response.missing_fields = ['time_text'];
    response.human_date = null;
    response.requested_datetime = null;
    response.resolved_requested_datetime = null;

    const responseBody = { ...response };
    response.response_body = responseBody;

    return [{ json: response }];
  }

  if (!resolvedDate) {
    response.ok = false;
    response.decision = 'datetime_clarification_needed';
    response.error_code = 'DATE_NOT_RESOLVED';
    response.reply = "Je n’ai pas pu interpréter correctement la date. Pouvez-vous me donner la date complète, par exemple mercredi 22 juillet ?";
    response.missing_fields = ['date_text'];
    return [{ json: response }];
  }

  if (!resolvedTime) {
    response.ok = false;
    response.decision = 'datetime_clarification_needed';
    response.error_code = 'TIME_NOT_RESOLVED';
    response.reply = "Pour quel horaire souhaitez-vous réserver ?";
    response.missing_fields = ['time_text'];
    return [{ json: response }];
  }

  const zoned = makeZonedIso(
    resolvedDate.year,
    resolvedDate.monthIndex,
    resolvedDate.day,
    resolvedTime.hour,
    resolvedTime.minute,
    timezone
  );

  if (zoned.utcDate < currentDate) {
    response.ok = false;
    response.decision = 'datetime_clarification_needed';
    response.error_code = 'REQUESTED_DATETIME_IN_PAST';
    response.reply = "Je n’ai pas pu interpréter correctement la date. Pouvez-vous me donner la date complète ?";
    response.missing_fields = ['date_text'];
    return [{ json: response }];
  }

  const resolvedHumanDate = formatDateHumanFr(zoned.iso, timezone);

  response.ok = true;
  response.decision = 'datetime_resolved';
  response.available = null;
  response.confirmed = false;
  response.requested_datetime = zoned.iso;
  response.resolved_requested_datetime = zoned.iso;
  response.human_date = resolvedHumanDate;
  response.resolved_human_date = resolvedHumanDate;
  response.restaurant_timezone = timezone;
  response.reply = `Très bien, j’ai compris : ${resolvedHumanDate}.`;
  response.missing_fields = [];

  return [{ json: response }];
}

if (req.action === 'check_availability') {
  if (missing.length > 0) {
    response.ok = true;
    response.decision = 'need_followup';
    response.needs_followup = true;
    response.missing_fields = missing;
    response.error_code = 'MISSING_REQUIRED_FIELDS';
    response.reply = "Il me manque la date, l’heure ou le nombre de personnes pour vérifier le créneau.";
    return [{ json: response }];
  }

  if (Number(req.party_size) > Number(restaurant.max_party_size || 12)) {
    response.ok = true;
    response.decision = 'unavailable';
    response.available = false;
    response.error_code = 'PARTY_SIZE_TOO_LARGE';
    response.reply = `Pour ${req.party_size} personnes, je dois transmettre la demande au restaurant. Le maximum standard est de ${restaurant.max_party_size || 12} personnes.`;
    return [{ json: response }];
  }

  if (isClosed) {
    response.ok = true;
    response.decision = 'unavailable';
    response.available = false;
    response.error_code = 'RESTAURANT_CLOSED';
    response.reply = `Désolé, le restaurant est fermé sur ce créneau${closure.closure_reason ? ` : ${closure.closure_reason}` : ''}. Souhaitez-vous choisir un autre horaire ?`;
    return [{ json: response }];
  }

  response.ok = true;
  response.available = true;

  if (!req.full_name) {
    response.decision = 'available_needs_name';
    response.needs_followup = true;
    response.missing_fields = ['full_name'];
    response.reply = `Le créneau est disponible pour ${req.party_size} personne${Number(req.party_size) > 1 ? 's' : ''}${humanDate ? ` le ${humanDate}` : ''}. À quel nom dois-je noter la réservation ?`;
    return [{ json: response }];
  }

  response.decision = 'available_waiting_confirmation';
  response.reply = `Le créneau est disponible pour ${req.party_size} personne${Number(req.party_size) > 1 ? 's' : ''}${humanDate ? ` le ${humanDate}` : ''}, au nom de ${req.full_name}. Souhaitez-vous confirmer la réservation ?`;
  return [{ json: response }];
}

if (req.action === 'create_reservation') {
  if (missing.length > 0) {
    response.ok = true;
    response.decision = 'need_followup';
    response.needs_followup = true;
    response.missing_fields = missing;
    response.error_code = 'MISSING_REQUIRED_FIELDS';
    response.reply = "Il me manque encore une information ou une confirmation explicite avant de créer la réservation.";
    return [{ json: response }];
  }

  if (Number(req.party_size) > Number(restaurant.max_party_size || 12)) {
    response.ok = true;
    response.decision = 'unavailable';
    response.available = false;
    response.error_code = 'PARTY_SIZE_TOO_LARGE';
    response.reply = `Pour ${req.party_size} personnes, je dois transmettre la demande au restaurant au lieu de confirmer automatiquement.`;
    return [{ json: response }];
  }

  if (isClosed) {
    response.ok = true;
    response.decision = 'unavailable';
    response.available = false;
    response.error_code = 'RESTAURANT_CLOSED';
    response.reply = `Je ne peux pas confirmer cette réservation : le restaurant est fermé sur ce créneau${closure.closure_reason ? ` : ${closure.closure_reason}` : ''}.`;
    return [{ json: response }];
  }

  if (reservationExists) {
    response.ok = true;
    response.decision = 'already_confirmed';
    response.available = true;
    response.confirmed = true;
    response.duplicate = true;
    response.reservation_id = existing.existing_reservation_id ?? null;
    response.client_id = existing.existing_client_id ?? null;
    response.reply = `Votre réservation est déjà confirmée${humanDate ? ` pour le ${humanDate}` : ''} au nom de ${req.full_name}, pour ${req.party_size} personne${Number(req.party_size) > 1 ? 's' : ''}.`;
    return [{ json: response }];
  }

  if (reservationCreated) {
    response.ok = true;
    response.decision = 'confirmed';
    response.available = true;
    response.confirmed = true;
    response.reservation_id = reservation.reservation_id ?? null;
    response.client_id = reservation.client_id ?? client.client_id ?? null;
    response.reply = `Votre réservation est confirmée${humanDate ? ` pour le ${humanDate}` : ''} au nom de ${req.full_name}, pour ${req.party_size} personne${Number(req.party_size) > 1 ? 's' : ''}. Merci et à bientôt.`;
    return [{ json: response }];
  }

  response.error_code = 'RESERVATION_NOT_CREATED';
  response.decision = 'technical_error';
  response.reply = "Je suis désolé, je n’ai pas pu créer la réservation automatiquement. Le restaurant pourra reprendre la demande.";
  return [{ json: response }];
}

if (req.action === 'log_conversation') {
  response.ok = true;
  response.decision = logSaved ? 'logged' : 'ignored';
  response.reply = logSaved ? "Conversation enregistrée." : "Aucune conversation à enregistrer.";
  response.log_saved = logSaved;
  response.log_id = log.log_id ?? null;
  return [{ json: response }];
}

return [{ json: response }];
